from html.parser import HTMLParser
from pathlib import Path
class P(HTMLParser):
    def __init__(self): super().__init__(); self.ids=[]; self.assets=[]
    def handle_starttag(self,tag,attrs):
        a=dict(attrs)
        if 'id' in a:self.ids.append(a['id'])
        for k in ('src','href'):
            if k in a:self.assets.append(a[k])
p=P();p.feed(Path('index.html').read_text())
dup={x for x in p.ids if p.ids.count(x)>1}
missing=[x for x in p.assets if x.startswith('./') and not Path(x[2:]).exists()]
print('HTML IDs:',len(p.ids),'duplicates:',dup or 'none')
print('Relative assets:',p.assets,'missing:',missing or 'none')
css=Path('styles.css').read_text(); print('CSS brace balance:',css.count('{')-css.count('}'))
